-- Patchnote 0.8.4 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.8.4', 'minor', '2026-05-24T10:00:00.000Z',
  'Configurable user tagging in Radarr/Sonarr — opt-in, no more hardcoded ndp- prefix',
  'Tagging utilisateur configurable côté Radarr/Sonarr — opt-in, plus de préfixe ndp- en dur',
  '[{"type":"feat","titleEn":"Per-user *arr tagging is now an opt-in setting","titleFr":"Le tagging utilisateur dans Radarr/Sonarr devient un réglage opt-in","descEn":"When Oscarr sent a request to Radarr or Sonarr, it auto-created a tag named `ndp-<username>` and attached it to the movie/series. The prefix was project-specific (legacy ''netflix du pauvre'' acronym) and carried no meaning for users joining Oscarr from other ecosystems. A new toggle under Admin → Configuration controls whether usernames are tagged at all. When enabled, the prefix is `oscarr-` (e.g. `oscarr-john`). The default is OFF — fresh installs ship with no tagging, keeping usernames out of the *arr UI unless the admin explicitly opts in.","descFr":"Quand Oscarr envoyait une requête à Radarr ou Sonarr, un tag `ndp-<username>` était créé automatiquement et attaché au film/série. Ce préfixe ''netflix du pauvre'' était spécifique au projet et n''avait aucun sens pour les nouveaux venus. Un toggle sous Admin → Configuration contrôle désormais si les noms d''utilisateur sont taggés. Quand activé, le préfixe devient `oscarr-` (ex. `oscarr-john`). Par défaut désactivé — les fresh installs n''envoient plus aucun tag, sauf opt-in explicite de l''admin."},{"type":"note","titleEn":"Existing `ndp-*` tags in your *arr instances are NOT migrated","titleFr":"Les anciens tags `ndp-*` dans vos instances *arr ne sont PAS migrés","descEn":"Oscarr does not touch tags it created in past versions. If you upgraded from a pre-0.8.4 install, the `ndp-<username>` tags previously attached to your library remain in Radarr/Sonarr as orphans — they no longer match anything Oscarr emits, but they''re harmless. Delete them manually in the *arr UI (Settings → Tags) if you want a clean slate. Going forward, if you enable the new toggle, fresh tags will use the `oscarr-` prefix instead.","descFr":"Oscarr ne touche pas aux tags qu''il a créés dans les versions précédentes. Si tu mets à jour depuis une install pré-0.8.4, les tags `ndp-<username>` attachés à ta bibliothèque restent dans Radarr/Sonarr en orphelins — ils ne correspondent plus à rien côté Oscarr, mais ils sont inoffensifs. Supprime-les à la main dans l''UI *arr (Settings → Tags) si tu veux une ardoise propre. Désormais, si tu actives le nouveau toggle, les nouveaux tags utilisent le préfixe `oscarr-`."}]'
) ON CONFLICT ("version") DO NOTHING;
